  content = '<h2>Criando APIs REST com Node.js</h2>
<p>REST (Representational State Transfer) é um padrão arquitetural para criar APIs escaláveis e mantíveis.</p>

<h3>Princípios REST</h3>
<ul>
<li><strong>Client-Server:</strong> Separação entre cliente e servidor</li>
<li><strong>Stateless:</strong> Cada requisição contém todas as informações necessárias</li>
<li><strong>Cacheable:</strong> Respostas podem ser cacheadas</li>
<li><strong>Uniform Interface:</strong> Interface consistente</li>
</ul>

<h3>Métodos HTTP</h3>
<pre><code>// GET - Obter dados
app.get("/usuarios/:id", (req, res) => {
  res.json({ id: req.params.id, nome: "João" });
});

// POST - Criar dados
app.post("/usuarios", (req, res) => {
  const novo_usuario = req.body;
  res.status(201).json(novo_usuario);
});

// PUT - Atualizar dados
app.put("/usuarios/:id", (req, res) => {
  res.json({ id: req.params.id, ...req.body });
});

// DELETE - Deletar dados
app.delete("/usuarios/:id", (req, res) => {
  res.status(204).send();
});</code></pre>

<h3>Status Codes</h3>
<ul>
<li><strong>2xx:</strong> Sucesso (200 OK, 201 Created, 204 No Content)</li>
<li><strong>3xx:</strong> Redirecionamento (301, 302, 304)</li>
<li><strong>4xx:</strong> Erro do cliente (400 Bad Request, 401 Unauthorized, 404 Not Found)</li>
<li><strong>5xx:</strong> Erro do servidor (500, 503)</li>
</ul>

<h3>Validação de Dados</h3>
<pre><code>const express = require("express");
const { body, validationResult } = require("express-validator");

app.post("/usuarios", [
  body("nome").notEmpty().withMessage("Nome é obrigatório"),
  body("email").isEmail().withMessage("Email inválido"),
  body("idade").isInt({ min: 18 }).withMessage("Idade mínima é 18")
], (req, res) => {
  const erros = validationResult(req);
  if (!erros.isEmpty()) {
    return res.status(400).json({ erros: erros.array() });
  }

  // Processar dados válidos
  res.json(req.body);
});</code></pre>

<h3>Tratamento de Erros</h3>
<pre><code>app.get("/usuarios/:id", async (req, res, next) => {
  try {
    const usuario = await Usuario.findById(req.params.id);
    if (!usuario) {
      return res.status(404).json({ erro: "Usuário não encontrado" });
    }
    res.json(usuario);
  } catch (erro) {
    next(erro);
  }
});

// Middleware de erro
app.use((erro, req, res, next) => {
  console.error(erro);
  res.status(500).json({ erro: "Erro interno do servidor" });
});</code></pre>

<h3>Autenticação com JWT</h3>
<pre><code>const jwt = require("jsonwebtoken");

// Gerar token
const token = jwt.sign({ id: usuario.id }, "SECRET_KEY", { expiresIn: "1h" });

// Verificar token
app.use((req, res, next) => {
  const token = req.headers.authorization?.split(" ")[1];
  if (!token) return res.status(401).send("Não autorizado");

  try {
    const decoded = jwt.verify(token, "SECRET_KEY");
    req.usuario = decoded;
    next();
  } catch (erro) {
    res.status(401).send("Token inválido");
  }
});</code></pre>

<h3>Na Prática</h3>
<p>Sempre valide dados de entrada, use status codes apropriados, e implemente autenticação para APIs protegidas.</p>',
