// Usar
const novo_usuario = new Usuario({ nome: "João", email: "joao@example.com" });
await novo_usuario.save();</code></pre>

<h3>Migrations</h3>
<p>Controle versão do schema do banco:</p>
<pre><code>// migrations/001_criar_usuarios.js
